class Solution:
    def digArtifacts(self, n, artifacts, dig):
        dug = set((r, c) for r, c in dig)
        count = 0
        for r1, c1, r2, c2 in artifacts:
            fully = True
            for r in range(r1, r2 + 1):
                for c in range(c1, c2 + 1):
                    if (r, c) not in dug:
                        fully = False
                        break
                if not fully:
                    break
            if fully:
                count += 1
        return count

