class Solution:
    def digArtifacts(self, n, artifacts, dig):
        dug = set((r, c) for r, c in dig)
        cell_to_artifact = {}
        remaining = []
        for idx, (r1, c1, r2, c2) in enumerate(artifacts):
            total = 0
            for r in range(r1, r2 + 1):
                for c in range(c1, c2 + 1):
                    cell_to_artifact[(r, c)] = idx
                    total += 1
            remaining.append(total)
        for r, c in dug:
            idx = cell_to_artifact.get((r, c))
            if idx is not None:
                remaining[idx] -= 1
        return sum(1 for v in remaining if v == 0)

