var digArtifacts = function(n, artifacts, dig) {
    const cellToArtifact = new Map();
    const remaining = [];
    for (let idx = 0; idx < artifacts.length; idx++) {
        const [r1, c1, r2, c2] = artifacts[idx];
        let total = 0;
        for (let r = r1; r <= r2; r++) {
            for (let c = c1; c <= c2; c++) {
                cellToArtifact.set(r * n + c, idx);
                total++;
            }
        }
        remaining.push(total);
    }
    const seenDig = new Set();
    for (const [r, c] of dig) {
        const key = r * n + c;
        if (seenDig.has(key)) continue;
        seenDig.add(key);
        if (cellToArtifact.has(key)) {
            const idx = cellToArtifact.get(key);
            remaining[idx]--;
        }
    }
    return remaining.filter(v => v === 0).length;
};
